const now = new Date();
const healthId = (typeof crypto !== 'undefined' && crypto.randomUUID)
  ? crypto.randomUUID()
  : 'health-' + now.getTime().toString(36) + '-' + Math.random().toString(36).slice(2, 10);
return [{
  json: {
    health_id: healthId,
    started_at: now.toISOString(),
    started_at_ms: now.getTime()
  }
}];

const init = $('Init Snapshot').first().json;
const items = $input.all();
const r = (items[0] && items[0].json) || {};
const httpCode = Number(r.statusCode ?? r.status ?? 0);
const errorRaw = r.error || r.message || null;
const ok = httpCode >= 200 && httpCode < 300;
return [{
  json: {
    service: 'n8n',
    status: ok ? 'ok' : 'fail',
    http_code: httpCode || null,
    latency_ms: Date.now() - init.started_at_ms,
    error: ok ? null : (errorRaw ? String(errorRaw).slice(0, 280) : 'non_2xx_or_no_response')
  }
}];

