const init = $('Init Snapshot').first().json;
const items = $input.all();
const r = (items[0] && items[0].json) || {};
const httpCode = Number(r.statusCode ?? r.status ?? 0);
const body = r.body || r;
const state = (body && body.instance && body.instance.state)
  || (body && body.state)
  || null;
const httpOk = httpCode >= 200 && httpCode < 300;
const stateOk = state === 'open';
const ok = httpOk && stateOk;
const errorRaw = r.error || (body && body.error) || null;
return [{
  json: {
    service: 'evolution',
    status: ok ? 'ok' : 'fail',
    http_code: httpCode || null,
    latency_ms: Date.now() - init.started_at_ms,
    evolution_state: state,
    error: ok
      ? null
      : (errorRaw
          ? String(errorRaw).slice(0, 280)
          : (!httpOk ? 'non_2xx_or_no_response' : ('state=' + String(state))))
  }
}];

