const init = $('Init Snapshot').first().json;
function safeFirst(nodeName) {
  try {
    const all = $(nodeName).all();
    if (!all || all.length === 0) return null;
    return all[0].json || null;
  } catch (e) {
    return null;
  }
}
const services = [
  safeFirst('Capture n8n')       || { service: 'n8n',       status: 'fail', http_code: null, latency_ms: null, error: 'capture_unavailable' },
  safeFirst('Capture Chatwoot')  || { service: 'chatwoot',  status: 'fail', http_code: null, latency_ms: null, error: 'capture_unavailable' },
  safeFirst('Capture Evolution') || { service: 'evolution', status: 'fail', http_code: null, latency_ms: null, error: 'capture_unavailable' },
  safeFirst('Capture OpenAI')    || { service: 'openai',    status: 'fail', http_code: null, latency_ms: null, error: 'capture_unavailable' },
  safeFirst('Capture Supabase')  || { service: 'supabase',  status: 'fail', http_code: null, latency_ms: null, error: 'capture_unavailable' },
];
const countsRaw = safeFirst('Counts 24h') || {};
const counts = {
  events_24h:       Number(countsRaw.events_24h ?? 0),
  infra_errors_24h: Number(countsRaw.infra_errors_24h ?? 0),
  opt_outs_24h:     Number(countsRaw.opt_outs_24h ?? 0),
  messages_24h:     Number(countsRaw.messages_24h ?? 0),
  leads_24h:        Number(countsRaw.leads_24h ?? 0),
  campaign_24h:     Number(countsRaw.campaign_24h ?? 0)
};
const raceRaw = safeFirst('Race Detection') || {};
const race_count = Number(raceRaw.race_count ?? 0);
const orphanRaw = $('Orphan Batches').all();
let orphan_keys = [];
try {
  if (Array.isArray(orphanRaw)) {
    for (const it of orphanRaw) {
      const j = it.json || {};
      if (Array.isArray(j.keys)) { orphan_keys = orphan_keys.concat(j.keys); }
      else if (typeof j === 'string') { orphan_keys.push(j); }
      else if (j && typeof j === 'object') {
        for (const k of Object.keys(j)) {
          if (k.startsWith('igor:batch:')) orphan_keys.push(k);
        }
      }
    }
  }
} catch (e) { orphan_keys = []; }
const orphan_batches_count = orphan_keys.length;
const threshold_breaches = [];
if (counts.infra_errors_24h > 50) threshold_breaches.push('infra_errors_24h>50');
if (counts.opt_outs_24h > 20)     threshold_breaches.push('opt_outs_24h>20');
for (const s of services) {
  if (s.status === 'fail') threshold_breaches.push('service_fail:' + s.service);
}
if (race_count > 0)                threshold_breaches.push('race');
if (orphan_batches_count > 5)      threshold_breaches.push('orphan_batches>5');
const failedServices = services.filter(s => s.status === 'fail').length;
let overall_status = 'healthy';
const hasDegraded = (counts.infra_errors_24h > 50)
  || (counts.opt_outs_24h > 20)
  || (failedServices >= 1);
if (hasDegraded) overall_status = 'degraded';
const hasCritical = (failedServices >= 2)
  || (race_count > 0)
  || (orphan_batches_count > 5);
if (hasCritical) overall_status = 'critical';
const endedAtMs = Date.now();
const payload = {
  health_id: init.health_id,
  started_at: init.started_at,
  ended_at: new Date(endedAtMs).toISOString(),
  duration_ms: endedAtMs - init.started_at_ms,
  services: services,
  counts: counts,
  race_count: race_count,
  orphan_batches_count: orphan_batches_count,
  orphan_keys_sample: orphan_keys.slice(0, 20),
  threshold_breaches: threshold_breaches,
  overall_status: overall_status
};
return [{
  json: {
    payload: payload,
    payload_json: JSON.stringify(payload),
    overall_status: overall_status
  }
}];
